"use client";

import { motion } from "framer-motion";
import { Code2, Lightbulb, Rocket, Users, WandSparkles } from "lucide-react";

import { BentoCard, BentoGrid } from "@/components/ui/bento-grid";
import { Project } from "@/data/projects";

type ProjectsProps = {
  id: string;
  projects: Project[];
};

export function Projects({ id, projects }: ProjectsProps) {
  const projectIcons = [Rocket, Users, WandSparkles, Code2, Lightbulb];
  const layoutClasses = [
    "lg:col-start-1 lg:col-end-2 lg:row-start-1 lg:row-end-3",
    "lg:col-start-2 lg:col-end-3 lg:row-start-1 lg:row-end-4",
    "lg:col-start-3 lg:col-end-4 lg:row-start-1 lg:row-end-2",
    "lg:col-start-1 lg:col-end-2 lg:row-start-3 lg:row-end-4",
    "lg:col-start-3 lg:col-end-4 lg:row-start-2 lg:row-end-4",
  ];

  return (
    <section id={id} className="scroll-mt-28 px-4 py-20 sm:px-6 lg:px-8">
      <div className="mx-auto flex max-w-6xl flex-col gap-12">
        <motion.div
          initial={{ opacity: 0, y: 24 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true, amount: 0.2 }}
          transition={{ duration: 0.6, ease: [0.22, 1, 0.36, 1] }}
          className="flex max-w-2xl flex-col gap-4 text-left"
        >
          <p className="text-sm font-medium uppercase tracking-[0.3em] text-accent">Projects</p>
          <h2 className="font-display text-3xl font-semibold tracking-tight text-foreground sm:text-4xl">
            Work built with execution in mind
          </h2>
          <p className="text-base leading-7 text-muted sm:text-lg">
            A mix of featured builds and fast-moving experiments shaped by product thinking.
          </p>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 24 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true, amount: 0.1 }}
          transition={{ duration: 0.6, delay: 0.08, ease: [0.22, 1, 0.36, 1] }}
        >
          <BentoGrid className="lg:grid-rows-3">
            {projects.map((project, index) => {
              const Icon = projectIcons[index % projectIcons.length];

              return (
                <BentoCard
                  key={project.title}
                  name={project.title}
                  Icon={Icon}
                  href={project.liveUrl}
                  cta={project.featured ? "Open featured project" : "Open project"}
                  className={layoutClasses[index % layoutClasses.length]}
                  background={
                    <div className="absolute inset-0">
                      <img
                        src={project.imageUrl}
                        alt={project.title}
                        className="h-full w-full object-cover opacity-30 transition duration-500 group-hover:scale-105 group-hover:opacity-40"
                      />
                      <div className="absolute inset-0 bg-gradient-to-t from-black via-black/70 to-black/15" />
                    </div>
                  }
                  description={
                    <div className="space-y-3">
                      <p>{project.description}</p>
                      <div className="flex flex-wrap gap-2">
                        {project.techStack.map((item) => (
                          <span
                            key={item}
                            className="rounded-full border border-white/10 bg-black/40 px-3 py-1 text-xs text-neutral-200 backdrop-blur-sm"
                          >
                            {item}
                          </span>
                        ))}
                      </div>
                    </div>
                  }
                  footer={
                    <div className="flex flex-wrap gap-3">
                      <a
                        href={project.githubUrl}
                        target="_blank"
                        rel="noreferrer"
                        className="pointer-events-auto text-sm font-medium text-neutral-100 transition duration-300 hover:text-accent"
                      >
                        GitHub
                      </a>
                      <a
                        href={project.liveUrl}
                        target="_blank"
                        rel="noreferrer"
                        className="pointer-events-auto text-sm font-medium text-neutral-100 transition duration-300 hover:text-accent"
                      >
                        Live Demo
                      </a>
                    </div>
                  }
                />
              );
            })}
          </BentoGrid>
        </motion.div>
      </div>
    </section>
  );
}
